/**
 * SMS notification adapter.
 *
 * Implements NotificationAdapter for the 'sms' channel.
 * Formats notification payloads as short text messages and delivers them
 * to a phone number resolved from the payload.
 */

import type { NotificationAdapter, NotificationResult } from './notification.adapter.js';
import type { NotificationPayload, NotificationType } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/**
 * A rendered SMS ready for delivery.
 */
export interface RenderedSms {
  to: string;
  message: string;
  type: NotificationType;
  metadata?: Record<string, unknown>;
}

/**
 * Delivery function signature. Can be replaced for testing or to swap SMS providers.
 */
export type SmsDeliveryFn = (sms: RenderedSms) => Promise<{ success: boolean; error?: string }>;

/**
 * Default delivery function that logs the SMS (for dev/test).
 */
const logDelivery =
  (logger: Logger): SmsDeliveryFn =>
  async (sms) => {
    logger.info(`Delivering SMS to ${sms.to}: ${sms.message}`);
    return { success: true };
  };

/**
 * SMS message templates keyed by notification type.
 * SMS messages are kept short since they have character limits.
 */
const DEFAULT_TEMPLATES: Record<NotificationType, (payload: NotificationPayload) => string> = {
  'order-confirmation': (p) =>
    `Order confirmed: ${p.subject}. ${p.body}`,
  'order-status-update': (p) =>
    `Order update: ${p.body}`,
  welcome: (p) =>
    `Welcome to TaskFlow Pro, ${p.recipient}! ${p.body}`,
  'account-update': (p) =>
    `Account updated: ${p.body}. Contact support if this wasn't you.`,
  'system-alert': (p) =>
    `[ALERT] ${p.subject}: ${p.body}`,
};

export class SmsAdapter implements NotificationAdapter {
  readonly channel = 'sms' as const;
  private logger = new Logger('SmsAdapter');
  private templates: Record<NotificationType, (payload: NotificationPayload) => string>;
  private deliverFn: SmsDeliveryFn;

  constructor(options?: {
    templates?: Partial<Record<NotificationType, (payload: NotificationPayload) => string>>;
    deliverFn?: SmsDeliveryFn;
  }) {
    this.templates = { ...DEFAULT_TEMPLATES, ...options?.templates };
    this.deliverFn = options?.deliverFn ?? logDelivery(this.logger);
  }

  /**
   * Resolve the recipient phone number from the payload.
   * If metadata contains an explicit `phoneNumber`, use that;
   * otherwise fall back to the payload's recipient field.
   */
  resolveRecipient(payload: NotificationPayload): string {
    const override = payload.metadata?.['phoneNumber'];
    if (typeof override === 'string' && override.length > 0) {
      return override;
    }
    return payload.recipient;
  }

  /**
   * Render the SMS message using the template for the notification type.
   */
  renderSms(payload: NotificationPayload): RenderedSms {
    const template = this.templates[payload.type];
    const to = this.resolveRecipient(payload);

    return {
      to,
      message: template(payload),
      type: payload.type,
      metadata: payload.metadata,
    };
  }

  /**
   * Send an SMS notification.
   * Renders the template, resolves the recipient, and delivers.
   * Never throws — returns a failed result on error.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    try {
      const sms = this.renderSms(payload);

      if (!sms.to || sms.to.trim().length === 0) {
        this.logger.warn('Cannot send SMS: no recipient');
        return { success: false, channel: 'sms', error: 'No recipient phone number' };
      }

      this.logger.info(`Sending ${payload.type} SMS to ${sms.to}`);
      const result = await this.deliverFn(sms);

      if (!result.success) {
        this.logger.error(`Failed to deliver SMS to ${sms.to}: ${result.error}`);
        return { success: false, channel: 'sms', error: result.error };
      }

      this.logger.info(`SMS delivered to ${sms.to}`);
      return { success: true, channel: 'sms' };
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      this.logger.error(`SMS send error: ${message}`);
      return { success: false, channel: 'sms', error: message };
    }
  }
}

import { describe, it, expect, vi } from 'vitest';
import { SmsAdapter } from '../../src/adapters/sms.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';
import type { SmsDeliveryFn } from '../../src/adapters/sms.adapter.js';

function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    recipient: '+15551234567',
    subject: 'Test Subject',
    body: 'Test body content',
    type: 'order-confirmation',
    channel: 'sms',
    ...overrides,
  };
}

describe('SmsAdapter', () => {
  describe('channel', () => {
    it('should have channel set to sms', () => {
      const adapter = new SmsAdapter();
      expect(adapter.channel).toBe('sms');
    });
  });

  describe('resolveRecipient', () => {
    it('should use payload recipient by default', () => {
      const adapter = new SmsAdapter();
      const payload = makePayload();
      expect(adapter.resolveRecipient(payload)).toBe('+15551234567');
    });

    it('should use phoneNumber from metadata when present', () => {
      const adapter = new SmsAdapter();
      const payload = makePayload({
        metadata: { phoneNumber: '+15559999999' },
      });
      expect(adapter.resolveRecipient(payload)).toBe('+15559999999');
    });

    it('should fall back to recipient when metadata phoneNumber is empty', () => {
      const adapter = new SmsAdapter();
      const payload = makePayload({
        metadata: { phoneNumber: '' },
      });
      expect(adapter.resolveRecipient(payload)).toBe('+15551234567');
    });
  });

  describe('renderSms', () => {
    it('should render order-confirmation template', () => {
      const adapter = new SmsAdapter();
      const payload = makePayload({ type: 'order-confirmation' });
      const sms = adapter.renderSms(payload);

      expect(sms.to).toBe('+15551234567');
      expect(sms.message).toContain('Order confirmed');
      expect(sms.message).toContain('Test body content');
    });

    it('should render order-status-update template', () => {
      const adapter = new SmsAdapter();
      const payload = makePayload({ type: 'order-status-update' });
      const sms = adapter.renderSms(payload);

      expect(sms.message).toContain('Order update');
    });

    it('should render welcome template', () => {
      const adapter = new SmsAdapter();
      const payload = makePayload({ type: 'welcome' });
      const sms = adapter.renderSms(payload);

      expect(sms.message).toContain('Welcome to TaskFlow Pro');
    });

    it('should render account-update template', () => {
      const adapter = new SmsAdapter();
      const payload = makePayload({ type: 'account-update' });
      const sms = adapter.renderSms(payload);

      expect(sms.message).toContain('Account updated');
      expect(sms.message).toContain('contact support');
    });

    it('should render system-alert template', () => {
      const adapter = new SmsAdapter();
      const payload = makePayload({ type: 'system-alert', subject: 'Disk Full' });
      const sms = adapter.renderSms(payload);

      expect(sms.message).toContain('[ALERT]');
      expect(sms.message).toContain('Disk Full');
    });

    it('should allow custom templates', () => {
      const adapter = new SmsAdapter({
        templates: {
          'order-confirmation': () => 'Custom SMS',
        },
      });
      const payload = makePayload({ type: 'order-confirmation' });
      const sms = adapter.renderSms(payload);

      expect(sms.message).toBe('Custom SMS');
    });
  });

  describe('send', () => {
    it('should deliver SMS successfully with default delivery', async () => {
      const adapter = new SmsAdapter();
      const result = await adapter.send(makePayload());

      expect(result.success).toBe(true);
      expect(result.channel).toBe('sms');
      expect(result.error).toBeUndefined();
    });

    it('should use custom delivery function', async () => {
      const deliverFn: SmsDeliveryFn = vi.fn(async () => ({ success: true }));
      const adapter = new SmsAdapter({ deliverFn });

      await adapter.send(makePayload());

      expect(deliverFn).toHaveBeenCalledOnce();
      const call = vi.mocked(deliverFn).mock.calls[0]![0];
      expect(call.to).toBe('+15551234567');
      expect(call.message).toContain('Order confirmed');
    });

    it('should return failure when delivery fails', async () => {
      const deliverFn: SmsDeliveryFn = vi.fn(async () => ({
        success: false,
        error: 'SMS gateway timeout',
      }));
      const adapter = new SmsAdapter({ deliverFn });

      const result = await adapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.channel).toBe('sms');
      expect(result.error).toBe('SMS gateway timeout');
    });

    it('should return failure when delivery throws', async () => {
      const deliverFn: SmsDeliveryFn = vi.fn(async () => {
        throw new Error('Connection refused');
      });
      const adapter = new SmsAdapter({ deliverFn });

      const result = await adapter.send(makePayload());

      expect(result.success).toBe(false);
      expect(result.channel).toBe('sms');
      expect(result.error).toBe('Connection refused');
    });

    it('should return failure when recipient is empty', async () => {
      const adapter = new SmsAdapter();
      const result = await adapter.send(makePayload({ recipient: '' }));

      expect(result.success).toBe(false);
      expect(result.error).toContain('No recipient');
    });

    it('should resolve recipient from metadata phoneNumber', async () => {
      const deliverFn: SmsDeliveryFn = vi.fn(async () => ({ success: true }));
      const adapter = new SmsAdapter({ deliverFn });

      await adapter.send(
        makePayload({ metadata: { phoneNumber: '+15559999999' } }),
      );

      const call = vi.mocked(deliverFn).mock.calls[0]![0];
      expect(call.to).toBe('+15559999999');
    });
  });
});

